import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

const API_BASE = "http://localhost:7000/api";

export default function Dashboard() {
  const [priceData, setPriceData] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [recent, setRecent] = useState([]);
  const [loading, setLoading] = useState(true);

  const [selectedCategory, setSelectedCategory] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  // Fetch price + category + recent data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [pricesRes, catsRes, recentRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`),
          axios.get(`${API_BASE}/admin/recent`),
        ]);
        setPriceData(pricesRes.data?.data || []);
        setCategoryList(catsRes.data?.categories || []);
        setRecent(Array.isArray(recentRes.data) ? recentRes.data : []);
      } catch (err) {
        console.error("Dashboard data fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Filter + group by date
  const filtered = priceData.filter((p) => {
    const date = new Date(p.validTill || p.createdAt);
    if (selectedCategory && p.category?.name !== selectedCategory) return false;
    if (startDate && new Date(startDate) > date) return false;
    if (endDate && new Date(endDate) < date) return false;
    return true;
  });

  const grouped = {};
  filtered.forEach((p) => {
    const dateKey = new Date(p.validTill || p.createdAt).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
    });
    if (!grouped[dateKey]) grouped[dateKey] = [];
    grouped[dateKey].push(p);
  });

  const labels = Object.keys(grouped);
  const avgBase = labels.map(
    (d) =>
      grouped[d].reduce((sum, p) => sum + (p.basePrice || 0), 0) / grouped[d].length
  );
  const avgDiff = labels.map(
    (d) =>
      grouped[d].reduce((sum, p) => sum + (p.difference || 0), 0) / grouped[d].length
  );

  const data = {
    labels,
    datasets: [
      {
        label: "Avg Base Price (₹)",
        data: avgBase,
        backgroundColor: "rgba(0, 123, 255, 0.7)",
        borderRadius: 6,
      },
      {
        label: "Avg Difference (₹)",
        data: avgDiff,
        backgroundColor: "rgba(255, 193, 7, 0.7)",
        borderRadius: 6,
      },
    ],
  };

  return (
    <div className="pro-dashboard">
      <h2 className="dash-title">📊 Price Analytics Overview</h2>
      <p className="dash-subtitle">
        Visualize category & product pricing trends with interactive filters.
      </p>

      {/* Filters */}
      <div className="filter-bar">
        <div className="filter-item">
          <label>Category:</label>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="">All</option>
            {categoryList.map((c) => (
              <option key={c._id} value={c.name}>
                {c.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-item">
          <label>From:</label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
          />
        </div>

        <div className="filter-item">
          <label>To:</label>
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
          />
        </div>
      </div>

      {/* Chart */}
      <div className="chart-section">
        {loading ? (
          <div className="loading">Loading chart...</div>
        ) : labels.length > 0 ? (
          <Bar
            data={data}
            options={{
              responsive: true,
              maintainAspectRatio: false,
              plugins: {
                legend: { position: "bottom" },
                tooltip: {
                  callbacks: {
                    label: (context) =>
                      `${context.dataset.label}: ₹${context.parsed.y.toFixed(2)}`,
                  },
                },
              },
              scales: {
                x: {
                  ticks: { color: "#6c757d" },
                  title: { display: true, text: "Date" },
                },
                y: {
                  beginAtZero: true,
                  ticks: { color: "#6c757d" },
                  title: { display: true, text: "Price (₹)" },
                },
              },
            }}
          />
        ) : (
          <div className="no-data">No data found for selected filters</div>
        )}
      </div>

      {/* Recent Activity */}
      <div className="activity-section">
        <h3>🕓 Recent Activity</h3>
        <div className="activity-feed">
          {recent.length === 0 ? (
            <p className="no-data">No recent activities found</p>
          ) : (
            recent.slice(0, 10).map((r, i) => (
              <div key={i} className="activity-card">
                <div className="activity-header">
                  <span className="action">{r.action}</span>
                  <span
                    className={`status ${
                      r.status === "Success" ? "success" : "fail"
                    }`}
                  >
                    {r.status}
                  </span>
                </div>
                <div className="activity-body">
                  <strong>{r.user}</strong> — {r.entity || "N/A"}
                </div>
                <div className="activity-date">
                  {new Date(r.date).toLocaleString("en-IN")}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
